const item = $input.first();
const binary = item.binary || {};

if (!binary.submission_file && binary.file) {
  binary.submission_file = binary.file;
}

const uploadFile = binary.submission_file;
if (!uploadFile) {
  throw new Error('Thieu file. Gui multipart/form-data voi field file la submission_file (hoac file).');
}

const filename = String(uploadFile.fileName || uploadFile.filename || '').toLowerCase();
const mimeType = String(uploadFile.mimeType || uploadFile.mimetype || '').toLowerCase();
const isPdf = filename.endsWith('.pdf') || mimeType === 'application/pdf';

if (!isPdf) {
  throw new Error('Chi ho tro file PDF cho workflow upload_answer');
}

return [{ json: item.json, binary }];

const extract = $('exam_detail').first()?.json?.extract_json;
const submission = $('add asignment').first()?.json;
const formData = $('Edit Fields2').first()?.json || {};

if (!submission?.id) {
  throw new Error('Khong tim thay submission id de cap nhat OCR result');
}

const submissionId = Number(submission.id);
const examId = Number(submission.exam_id || 0);
const studentCode = String(formData['Mã sinh viên'] || '').replace(/'/g, "''");
const studentName = String(formData.name || '').replace(/'/g, "''");
const classCode = String(formData.class_code || '').replace(/'/g, "''");
const extractJsonStr = JSON.stringify(extract || []).replace(/'/g, "''");
const payload = JSON.stringify({ extract_json: extract || [] }).replace(/'/g, "''");

const sql = `
UPDATE submissions
SET
  submission_extract = '${extractJsonStr}'::jsonb,
  status = 'extracted',
  updated_at = NOW()
WHERE id = ${submissionId};

INSERT INTO system_logs (
  log_type,
  ref_table,
  ref_id,
  exam_id,
  submission_id,
  student_code,
  student_name,
  class_code,
  workflow_execution_id,
  model_name,
  status,
  message,
  response_payload,
  created_at
) VALUES (
  'submission_extract',
  'submissions',
  ${submissionId},
  ${examId},
  ${submissionId},
  NULLIF('${studentCode}', ''),
  NULLIF('${studentName}', ''),
  NULLIF('${classCode}', ''),
  '{{ $execution.id }}',
  'mistral-ocr-latest + gpt-4.1-mini',
  'success',
  'OCR va trich xuat JSON thanh cong - luu vao submission_extract',
  '${payload}'::jsonb,
  NOW()
);`;

return [{ json: { id: submissionId, sql } }];

const textData = $input.first().json.text || '[]';
const extractJson = JSON.parse(textData);

return [
  {
    json: {
      extract_json: extractJson
    }
  }
];

