const exam = $input.first()?.json || {};
const examId = Number($('Edit Fields2').first()?.json?.exam_id || 0);

if (!Number.isFinite(examId) || examId <= 0) {
  throw new Error('exam_id khong hop le hoac bi thieu trong request');
}

if (!exam.id) {
  throw new Error(`Khong tim thay exam voi exam_id=${examId}`);
}

if (String(exam.status || '').toLowerCase() !== 'active') {
  throw new Error(`Exam ${examId} khong o trang thai active`);
}

return $input.all();

